"use client";

import * as React from "react";
import {
  Container,
  Button,
  Badge,
  Card,
  CardHeader,
  CardTitle,
  CardDescription,
  CardContent,
  CardFooter,
  ToggleGroup,
  ToggleGroupItem,
  Table,
  TableHeader,
  TableBody,
  TableHead,
  TableRow,
  TableCell,
  TableCaption,
  Accordion,
  AccordionItem,
  AccordionTrigger,
  AccordionContent,
  Separator,
  cn,
} from "@gunjo/ui";
import { IconCheck, IconMinus } from "@tabler/icons-react";
import {
  plans,
  comparison,
  faqs,
  priceFor,
  type BillingPeriod,
  type Cell,
  YEARLY_DISCOUNT_LABEL,
} from "./data";

/* -------------------------------------------------------------------------- */
/* Comparison matrix cell with an accessible text alternative                  */
/* -------------------------------------------------------------------------- */
function ComparisonCell({ value }: { value: Cell }) {
  if (value === true) {
    return (
      <span className="inline-flex items-center justify-center text-success-strong">
        <IconCheck className="h-4 w-4" aria-hidden="true" />
        <span className="sr-only">対応</span>
      </span>
    );
  }
  if (value === false) {
    return (
      <span className="inline-flex items-center justify-center text-muted-foreground">
        <IconMinus className="h-4 w-4" aria-hidden="true" />
        <span className="sr-only">非対応</span>
      </span>
    );
  }
  return <span className="text-sm">{value}</span>;
}

/* -------------------------------------------------------------------------- */
/* Plan card (composed from Card primitives — PricingTemplate can't do this)   */
/* -------------------------------------------------------------------------- */
function PlanCard({
  planId,
  period,
}: {
  planId: string;
  period: BillingPeriod;
}) {
  const plan = plans.find((p) => p.id === planId)!;
  const price = priceFor(plan, period);
  const recommended = Boolean(plan.recommended);

  return (
    <Card
      className={cn(
        "relative h-full",
        recommended
          ? "border-primary ring-1 ring-primary shadow-md"
          : undefined
      )}
    >
      {recommended ? (
        <div className="absolute -top-3 left-1/2 -translate-x-1/2">
          <Badge variant="default">一番人気</Badge>
        </div>
      ) : null}
      <CardHeader>
        <CardTitle as="h3" className="text-lg">
          {plan.name}
        </CardTitle>
        <CardDescription>{plan.description}</CardDescription>
      </CardHeader>
      <CardContent className="flex flex-1 flex-col gap-4">
        <div>
          <div className="flex items-baseline gap-1">
            <span className="text-3xl font-bold tracking-tight">
              {price.display}
            </span>
            {price.suffix ? (
              <span className="text-sm text-muted-foreground">
                {price.suffix}
              </span>
            ) : null}
          </div>
          {price.billedNote ? (
            <p className="mt-1 text-xs text-muted-foreground">
              {price.billedNote}
            </p>
          ) : null}
        </div>
        <ul className="flex flex-col gap-2">
          {plan.highlights.map((h) => (
            <li key={h} className="flex items-start gap-2 text-sm">
              <IconCheck
                className="mt-0.5 h-4 w-4 shrink-0 text-success-strong"
                aria-hidden="true"
              />
              <span>{h}</span>
            </li>
          ))}
        </ul>
      </CardContent>
      <CardFooter>
        <Button
          variant={recommended ? "primary" : "outline"}
          className="w-full"
          asChild
        >
          <a href="#" aria-label={`${plan.cta}（${plan.name}プラン）`}>
            {plan.cta}
          </a>
        </Button>
      </CardFooter>
    </Card>
  );
}

/* -------------------------------------------------------------------------- */
/* Page                                                                        */
/* -------------------------------------------------------------------------- */
export default function PricingPage() {
  const [period, setPeriod] = React.useState<BillingPeriod>("monthly");

  return (
    <main className="flex-1 py-12 sm:py-16">
      <Container size="xl" className="flex flex-col gap-16">
        {/* Header --------------------------------------------------------- */}
        <header className="flex flex-col items-center gap-4 text-center">
          <h1 className="text-4xl font-bold tracking-tight sm:text-5xl">
            あなたの成長に合わせて選べる料金
          </h1>
          <p className="max-w-2xl text-balance text-muted-foreground">
            無料で始めて、成長したらアップグレード。すべてのプランに、基本の
            エディター、無制限の閲覧ユーザー、そして稼働率99.9%のお約束が含まれます。
          </p>

          {/* Billing toggle ---------------------------------------------- */}
          <div className="mt-2 flex flex-col items-center gap-2">
            <ToggleGroup
              type="single"
              value={period}
              onValueChange={(v) => {
                if (v) setPeriod(v as BillingPeriod);
              }}
              aria-label="請求期間"
              className="rounded-lg border p-1"
            >
              <ToggleGroupItem
                value="monthly"
                variant="outline"
                aria-label="月額払い"
              >
                月額
              </ToggleGroupItem>
              <ToggleGroupItem
                value="yearly"
                variant="outline"
                aria-label="年額払い"
              >
                年額
              </ToggleGroupItem>
            </ToggleGroup>
            {/* NOTE: this is a <div>, not a <p>: Badge renders a block <div>
                and has no `as`/`asChild` to go inline, so a <p> wrapper trips
                "div cannot be a descendant of p" hydration errors. */}
            <div
              className="flex min-h-5 items-center gap-1.5 text-xs text-muted-foreground"
              aria-live="polite"
            >
              {period === "yearly" ? (
                <>
                  <Badge variant="secondary">{YEARLY_DISCOUNT_LABEL}</Badge>
                  <span>年額払いで2か月分お得になっています。</span>
                </>
              ) : (
                <span>年額払いなら{YEARLY_DISCOUNT_LABEL.toLowerCase()}。</span>
              )}
            </div>
          </div>
        </header>

        {/* Plan cards ----------------------------------------------------- */}
        <section aria-labelledby="plans-heading">
          <h2 id="plans-heading" className="sr-only">
            Plans
          </h2>
          <div className="grid grid-cols-1 gap-6 sm:grid-cols-2 lg:grid-cols-4">
            {plans.map((plan) => (
              <PlanCard key={plan.id} planId={plan.id} period={period} />
            ))}
          </div>
        </section>

        {/* Comparison matrix --------------------------------------------- */}
        <section aria-labelledby="compare-heading" className="flex flex-col gap-6">
          <div className="flex flex-col gap-2">
            <h2
              id="compare-heading"
              className="text-2xl font-bold tracking-tight"
            >
              全機能を比較
            </h2>
            <p className="text-sm text-muted-foreground">
              各プランに含まれる内容を並べて確認できます
              {period === "yearly" ? "（上部の料金は年額表示です）" : ""}。
            </p>
          </div>

          <Table>
            <TableCaption>
              全 {plans.length} プランの機能比較。チェックは対応、ダッシュは
              非対応を表します。
            </TableCaption>
            <TableHeader>
              <TableRow>
                <TableHead scope="col" className="w-[40%] min-w-[180px]">
                  機能
                </TableHead>
                {plans.map((plan) => (
                  <TableHead
                    key={plan.id}
                    scope="col"
                    className={cn(
                      "text-center",
                      plan.recommended && "text-foreground"
                    )}
                  >
                    <span className="inline-flex flex-col items-center gap-1">
                      <span className="font-semibold">{plan.name}</span>
                      {plan.recommended ? (
                        <Badge variant="default" className="font-medium">
                          人気
                        </Badge>
                      ) : null}
                    </span>
                  </TableHead>
                ))}
              </TableRow>
            </TableHeader>
            <TableBody>
              {comparison.map((section) => (
                <React.Fragment key={section.title}>
                  <TableRow className="bg-muted/40 hover:bg-muted/40">
                    <TableHead
                      scope="colgroup"
                      colSpan={plans.length + 1}
                      className="bg-transparent text-foreground"
                    >
                      {section.title}
                    </TableHead>
                  </TableRow>
                  {section.rows.map((row) => (
                    <TableRow key={row.feature}>
                      <TableHead
                        scope="row"
                        className="bg-transparent font-normal text-foreground"
                      >
                        {row.feature}
                      </TableHead>
                      {plans.map((plan) => (
                        <TableCell key={plan.id} className="text-center">
                          <ComparisonCell value={row.values[plan.id]} />
                        </TableCell>
                      ))}
                    </TableRow>
                  ))}
                </React.Fragment>
              ))}
            </TableBody>
          </Table>
        </section>

        {/* FAQ ------------------------------------------------------------ */}
        <section aria-labelledby="faq-heading" className="flex flex-col gap-6">
          <h2 id="faq-heading" className="text-2xl font-bold tracking-tight">
            よくあるご質問
          </h2>
          <Accordion type="single" collapsible className="rounded-lg">
            {faqs.map((faq, i) => (
              <AccordionItem key={faq.q} value={`faq-${i}`}>
                <AccordionTrigger indicator="plus">{faq.q}</AccordionTrigger>
                <AccordionContent>{faq.a}</AccordionContent>
              </AccordionItem>
            ))}
          </Accordion>
        </section>

        {/* Final CTA band ------------------------------------------------- */}
        <section aria-labelledby="cta-heading">
          <div className="flex flex-col items-center gap-5 rounded-2xl border bg-card p-10 text-center">
            <h2
              id="cta-heading"
              className="text-2xl font-bold tracking-tight sm:text-3xl"
            >
              さっそく始めましょう
            </h2>
            <p className="max-w-xl text-muted-foreground">
              プロを14日間無料でお試しいただけます。クレジットカードは不要。いつでも解約できます。
            </p>
            <Separator className="max-w-xs" />
            <div className="flex flex-col gap-3 sm:flex-row">
              <Button size="lg" variant="primary" asChild>
                <a href="#">無料トライアルを始める</a>
              </Button>
              <Button size="lg" variant="outline" asChild>
                <a href="#">営業に相談する</a>
              </Button>
            </div>
          </div>
        </section>
      </Container>
    </main>
  );
}

// Pricing data for the cold-test pricing comparison page.
// Prices are monthly-equivalent USD. Yearly billing = pay for 10 months (2 months free).

export type BillingPeriod = "monthly" | "yearly";

export interface Plan {
  id: string;
  name: string;
  /** Monthly price in USD when billed monthly. null = custom/contact sales. */
  monthly: number | null;
  description: string;
  /** Short feature bullets shown inside the plan card. */
  highlights: string[];
  cta: string;
  /** Exactly one plan should set this true. */
  recommended?: boolean;
}

export const YEARLY_MONTHS_CHARGED = 10; // 2 months free
export const YEARLY_DISCOUNT_LABEL = "2か月分お得";

