/** Resolve the per-month displayed price for a plan + billing period. */
export function priceFor(plan: Plan, period: BillingPeriod): {
  display: string;
  suffix: string | null;
  billedNote: string | null;
} {
  if (plan.monthly === null) {
    return { display: "お見積り", suffix: null, billedNote: "ご相談ください" };
  }
  if (plan.monthly === 0) {
    return { display: "¥0", suffix: "/月", billedNote: "ずっと無料" };
  }
  if (period === "monthly") {
    return {
      display: `¥${plan.monthly.toLocaleString("ja-JP")}`,
      suffix: "/月",
      billedNote: "月額払い",
    };
  }
  // Yearly: charge 10 months, show effective monthly rate.
  const yearlyTotal = plan.monthly * YEARLY_MONTHS_CHARGED;
  const effectiveMonthly = Math.round(yearlyTotal / 12);
  return {
    display: `¥${effectiveMonthly.toLocaleString("ja-JP")}`,
    suffix: "/月",
    billedNote: `年額 ¥${yearlyTotal.toLocaleString("ja-JP")} 一括払い`,
  };
}

// --- Comparison matrix -------------------------------------------------------
